import React, { useState } from "react";

const mockDB = {
  "KL34F500":   { status: "STOLEN", location: "Guduvancherry Signal",   time: "14:32:10" },
  "TN09AB1234": { status: "SAFE",   location: "Tambaram Toll Gate",      time: "14:45:22" },
  "MH12DE4321": { status: "STOLEN", location: "Perungalathur Junction",  time: "13:10:05" },
};

function SearchPanel() {
  const [query, setQuery]   = useState("");
  const [result, setResult] = useState(null);
  const [searched, setSearched] = useState(false);

  const handleSearch = () => {
    const key = query.trim().toUpperCase();
    if (!key) return;
    setSearched(true);
    setResult(mockDB[key] || null);
  };

  const handleKeyDown = (e) => {
    if (e.key === "Enter") handleSearch();
  };

  return (
    <div className="panel search-panel">
      <div className="panel-header">
        <h3 className="panel-title">🔍 Vehicle Number Search</h3>
      </div>

      <div className="search-row">
        <input
          className="search-input"
          type="text"
          placeholder="Enter vehicle plate number (e.g. KL34F500)"
          value={query}
          onChange={(e) => { setQuery(e.target.value); setSearched(false); setResult(null); }}
          onKeyDown={handleKeyDown}
        />
        <button className="search-btn" onClick={handleSearch}>Search</button>
      </div>

      {searched && (
        <div className={`search-result ${result ? (result.status === "STOLEN" ? "result-stolen" : "result-safe") : "result-notfound"}`}>
          {result ? (
            <>
              <div className="result-row">
                <span className="result-key">Status</span>
                <span className={`result-val ${result.status === "STOLEN" ? "text-red" : "text-green"}`}>
                  {result.status === "STOLEN" ? "⚠ STOLEN" : "✔ SAFE"}
                </span>
              </div>
              <div className="result-row">
                <span className="result-key">Last Detected Location</span>
                <span className="result-val">{result.location}</span>
              </div>
              <div className="result-row">
                <span className="result-key">Last Detected Time</span>
                <span className="result-val">{result.time}</span>
              </div>
            </>
          ) : (
            <p className="result-notfound-text">No record found for plate <strong>{query.toUpperCase()}</strong></p>
          )}
        </div>
      )}
    </div>
  );
}

export default SearchPanel;
